// left[node] == -1 means leaf node
func eval(node int, f []float64) float64 {
	for {
		if left[node] < 0 {
			return value[node]
		}
		v := f[feature[node]]
		m := missType[node]
		if math.IsNaN(v) {
			if m == 2 {
				node = defaultTo[node]
				continue
			}
			v = 0.0 // missing_type None/Zero: NaN acts as 0
		}
		if m == 1 && v >= -1e-35 && v <= 1e-35 {
			node = defaultTo[node]
			continue
		}
		if v <= threshold[node] {
			node = left[node]
		} else {
			node = right[node]
		}
	}
}

// Predict returns the regression score for feature vector f.
func Predict(f []float64) float64 {
	s := 0.0
	for _, root := range roots {
		s += eval(root, f)
	}
	return s
}
